DBGFILE="/tmp/symbols/libmonosgen-2.0.so.dbg"

# Get symbols near those addresses
aarch64-linux-gnu-nm -C "$DBGFILE" 2>/dev/null | awk '$1 != "" {printf "0x%s %s %s\n", $1, $2, $3}' | sort | awk '
