arguments.command:
# The addresses fall in BSS data region (in_labels table). These might be 
# computed-goto targets inside the interpreter. Let me check the .text section
# to see if there are functions at these VAs, or if they're truly data.
DBGFILE="/tmp/symbols/libmonosgen-2.0.so.dbg"

# Check which section these addresses belong to
aarch64-linux-gnu-readelf -S "$DBGFILE" 2>/dev/null | grep -E '\.text|\.bss|\.data|\.rodata' | head -10

echo "---"
# Try looking up in the .symtab for function symbols (type T/t) near these addresses
aarch64-linux-gnu-nm -C "$DBGFILE" 2>/dev/null | grep -E "^[0-9a-f]+ [Tt]" | sort | awk '
{
  addr = strtonum("0x" $1)
  if (addr <= 0x2f4b20) { fn1_addr = $1; fn1_name = $3 }
  if (addr <= 0x2f4c84) { fn2_addr = $1; fn2_name = $3 }
}
END {
  printf "Nearest code function to 0x2f4b20: %s at 0x%s (offset +0x%x)\n", fn1_name, fn1_addr, 0x2f4b20 - strtonum("0x" fn1_addr)
  printf "Nearest code function to 0x2f4c84: %s at 0x%s (offset +0x%x)\n", fn2_name, fn2_addr, 0x2f4c84 - strtonum("0x" fn2_addr)
}'

