# Get full section details including sizes to confirm which section contains these addresses
LIBFILE="/tmp/symbols/libmonosgen-2.0.so"
aarch64-linux-gnu-readelf -S -W "$LIBFILE" 2>/dev/null | grep -E '^\s+\[' | grep -E '(text|data\.rel\.ro)' 

echo "---"
# Check if .text covers these addresses
aarch64-linux-gnu-readelf -S -W "$LIBFILE" 2>/dev/null | awk '/\.text/ && /PROGBITS/ { 
  addr = strtonum("0x" $4); size = strtonum("0x" $6)
  printf ".text: 0x%x - 0x%x (size 0x%x)\n", addr, addr+size, size
}
/data\.rel\.ro/ && /PROGBITS/ {
  addr = strtonum("0x" $4); size = strtonum("0x" $6)
  printf ".data.rel.ro: 0x%x - 0x%x (size 0x%x)\n", addr, addr+size, size
}'

